const body = $input.first().json.body || $input.first().json;
const text = body.text || body.content || '';
const filename = body.filename || 'document.txt';

if (!text) {
  throw new Error('No text content provided. Send JSON with a "text" field.');
}

const truncated = text.length > 3000 ? text.substring(0, 3000) + '...' : text;

return [{ json: { text: truncated, filename, char_count: text.length } }];

const response = $input.first().json;
const rawContent = response.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  parsed = { error: 'Failed to parse AI response', raw: rawContent };
}

const filename = $('Extract Text').first().json.filename;
const charCount = $('Extract Text').first().json.char_count;

return [{
  json: {
    filename,
    char_count: charCount,
    category: parsed.category || 'Unknown',
    confidence: parsed.confidence || 'low',
    summary: parsed.summary || '',
    key_entities: parsed.key_entities || [],
    processed_at: new Date().toISOString()
  }
}];
